INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-660afcb0-moex-00048', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '主管機關為推動各機關（構）、公營事業機構節能減碳，依職權訂定獎勵節能要點，各機關（構） 如經主管機關評比為節能措施實施成效良好者，將給予獎勵。關於此要點之法律性質，下列敘述 何者正確？', '["本要點為實現重要公共利益而訂定，適用範圍及於主管機關之外的機關或機構，性質屬法規命令", "本要點為主管機關辦理節能措施評比獎勵之依據，屬機關業務處理的一般性規定，故為指令", "即使相關法規未課予主管機關推動節能減碳措施之義務，其仍可訂定要點執行評比與獎勵", "因獎勵涉及動用國家財政預算，為落實民主原則，應依立法院通過法律明文授權始得辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00049', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '考生持國立大學畢業證書報名參加國家考試，該畢業證書對辦理考試機關之拘束力，係屬下列何者？', '["形式存續力", "構成要件效力", "執行力", "確認效力 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00050', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '依行政程序法規定，下列何者非屬應予廢止之情形？', '["主管機關核發建築執照後發現申請人於申請時所提出之土地使用同意書為偽造", "主管機關准予變更土地編定時，附記申請人應提出土地使用計畫書並配置必要公共設施，事後 申請人並未履行", "勞動部核發外籍家庭照護工聘用許可後，雇主死亡", "外國人經內政部移民署核發居留許可入境後，其有重大危害公共安全之情形"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00051', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '關於行政機關之管轄，下列敘述何者正確？', '["行政機關對事件管轄權之有無，應依職權調查；其認無管轄權者，應即移送司法機關，並通知 當事人", "行政機關得依法規將其權限之一部分，委任民間團體或個人辦理", "行政機關因業務上之需要，得依法規將其權限之一部分，委託不相隸屬之行政機關執行之", "數行政機關於管轄權有爭議時，應由司法機關指定管轄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00052', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '關於行政契約之敘述，下列何者正確？', '["行政契約與行政處分乃不同性質之行政作用，故行政機關有作成行政處分權限時，即不可再締 結行政契約", "國民住宅之買賣契約屬於取代行政處分之行政契約", "行政契約原則上是屬於要式行為", "行政契約依約定內容履行將侵害第三人之權利者，應經該第三人書面或口頭之同意，始生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00053', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '主管機關建議農民甲停種作物並輔導休耕，甲表示不同意，依行政程序法規定，該機關應如何為 適法之處理？', '["以甲為相對人作成行政處分，命其休耕", "對甲裁處罰鍰，並於甲休耕前，得連續處罰", "應派員親至當地強制執行休耕", "應停止繼續建議或輔導"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00054', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '關於行政罰管轄機關及裁處程序之敘述，下列何者正確？', '["一行為違反數個行政法上義務而應處罰鍰，數機關均有管轄權者，由處理在先之機關管轄", "行政機關對現行違反行政法上義務之行為人，得即時制止其行為", "一行為違反同一行政法上義務，數機關均有管轄權者，由其共同上級機關管轄", "得沒入之物，得扣留之，行政機關為沒入之裁處前，應舉行聽證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00055', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '關於行政執行之敘述，下列何者錯誤？', '["行政機關依法作成行政處分，課予人民義務，不表示即可以強制手段貫徹之，因此行政執行須 另有法律依據，且須符合動用強制手段之法定要件與程序", "行政機關於動用強制手段前，須於處分書或另以書面限定相當之履行期限，並告知不履行之後果", "行政強制措施若涉及剝奪人民身體自由者，例如管收，基於憲法第8條之規定，須經法院始得 為之", "行為或不行為義務之執行，由原處分機關或該管行政機關為之；公法上金錢給付義務逾期不履 行者，亦同 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00056', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '關於政府資訊公開法之敘述，下列何者正確？', '["申請人對於政府機關就其申請提供政府資訊所為之決定不服者，不得提起行政救濟", "政府機關提供政府資訊時，得按申請政府資訊之用途，向申請人收取費用", "申請政府機關提供政府資訊，以具有中華民國國籍者為限", "人民請求政府資訊公開，以維護其法律上利益有必要者為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00057', 'promotion-660afcb0', 'promotion-660afcb0-moex-114-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '依司法實務見解，受理訴願機關撤銷原行政處分之全部時，下列敘述何者正確？', '["訴願管轄機關得逕為更不利益之變更決定，如發回原行政處分機關另為處分時亦得為更不利益 之處分", "訴願管轄機關不得為更不利益之變更決定，但發回原行政處分機關另為處分時得為更不利益之 處分", "訴願管轄機關得逕為更不利益之變更決定，但發回原行政處分機關另為處分時不得為更不利益 之處分", "訴願管轄機關不得逕為更不利益之變更決定，如發回原處分行政機關另為處分時亦不得為更不 利益之處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:51+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "143", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL)
